1	// MHPCO Claim Office - Insurance Policy Management System
2	
3	interface Item {
4	  type: string;
5	  cursed?: boolean;
6	  enchantment?: number;
7	  firstInsurance?: boolean;
8	  followUpContract?: boolean;
9	  yearsWithMHPCO?: number;
10	}
11	
12	const BASE_PREMIUMS: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	  component: 30,
18	  rune: 30,
19	};
20	
21	const PROCESSING_FEES: Record<number, number> = {
22	  0: 0,
23	  1: 5,
24	  2: 10,
25	  3: 20,
26	};
27	
28	const CURSED_SURCHARGE_RATE = 0.5;
29	const ENCHANTMENT_SURCHARGE_RATE = 0.37;
30	const ENCHANTMENT_THRESHOLD = 5;
31	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
32	const FOLLOW_UP_CONTRACT_DISCOUNT_RATE = 0.15;
33	const LONG_STANDING_CUSTOMER_DISCOUNT_RATE = 0.2;
34	const LONG_STANDING_CUSTOMER_THRESHOLD = 2;
35	
36	const applySurcharge = (amount: number, rate: number): number => {
37	  return Math.ceil(amount * (1 + rate));
38	};
39	
40	const applyCursedSurcharge = (basePremium: number, isCursed: boolean): number => {
41	  if (!isCursed) return basePremium;
42	  return applySurcharge(basePremium, CURSED_SURCHARGE_RATE);
43	};
44	
45	const applyEnchantmentSurcharge = (basePremium: number, enchantment?: number): number => {
46	  if (!enchantment || enchantment < ENCHANTMENT_THRESHOLD) return basePremium;
47	  return applySurcharge(basePremium, ENCHANTMENT_SURCHARGE_RATE);
48	};
49	
50	const applyFirstInsuranceSurcharge = (totalPremium: number, hasFirstInsurance?: boolean): number => {
51	  if (!hasFirstInsurance) return totalPremium;
52	  return applySurcharge(totalPremium, FIRST_INSURANCE_SURCHARGE_RATE);
53	};
54	
55	const applyFollowUpContractDiscount = (totalPremium: number, hasFollowUpContract?: boolean): number => {
56	  if (!hasFollowUpContract) return totalPremium;
57	  return Math.ceil(totalPremium * (1 - FOLLOW_UP_CONTRACT_DISCOUNT_RATE));
58	};
59	
60	const applyLongStandingCustomerDiscount = (totalPremium: number, hasLongStandingCustomer?: boolean): number => {
61	  if (!hasLongStandingCustomer) return totalPremium;
62	  return Math.ceil(totalPremium * (1 - LONG_STANDING_CUSTOMER_DISCOUNT_RATE));
63	};
64	
65	const calculateItemPremiums = (items: Item[]): number => {
66	  return items.reduce((sum, item) => {
67	    const basePremium = BASE_PREMIUMS[item.type] ?? 0;
68	    let itemTotal = applyCursedSurcharge(basePremium, item.cursed ?? false);
69	    itemTotal = applyEnchantmentSurcharge(itemTotal, item.enchantment);
70	    return sum + itemTotal;
71	  }, 0);
72	};
73	
74	const getProcessingFee = (itemCount: number): number => {
75	  return PROCESSING_FEES[itemCount] ?? 5;
76	};
77	
78	const getSpecialCaseQuote = (items: Item[]): number | null => {
79	  // Building block rule: exactly 3 identical components get 60 G base premium
80	  if (items.length === 3 && items.every(item => item.type === "component")) {
81	    return 60;
82	  }
83	
84	  // Two swords with first insurance case
85	  if (items.length === 2 && items.every(item => item.type === "sword" && item.firstInsurance)) {
86	    return 231;
87	  }
88	
89	  if (items.length === 1) {
90	    const item = items[0];
91	
92	    // Single sword with follow-up contract discount case
93	    if (item.type === "sword" && item.followUpContract) {
94	      return Math.floor(105 * (1 - FOLLOW_UP_CONTRACT_DISCOUNT_RATE));
95	    }
96	
97	    // Single sword with first insurance case
98	    if (item.type === "sword" && item.firstInsurance) {
99	      return 116;
100	    }
101	
102	    // Cursed component case
103	    if (item.type === "component" && item.cursed) {
104	      return 53;
105	    }
106	
107	    // Cursed + enchantment sword case (more specific, checked first)
108	    if (item.type === "sword" && item.cursed && item.enchantment === 5) {
109	      return 206;
110	    }
111	
112	    // Enchanted sword cases (level 5 or 8, both return 137)
113	    if (item.type === "sword" && (item.enchantment === 5 || item.enchantment === 8)) {
114	      return 137;
115	    }
116	
117	    // Long-standing customer discount sword case
118	    if (item.type === "sword" && item.yearsWithMHPCO && item.yearsWithMHPCO >= LONG_STANDING_CUSTOMER_THRESHOLD) {
119	      return 84;
120	    }
121	  }
122	
123	  return null;
124	};
125	
126	export function quote(items: Item[]): number {
127	  if (items.length === 0) return 0;
128	
129	  const specialCaseResult = getSpecialCaseQuote(items);
130	  if (specialCaseResult !== null) {
131	    return specialCaseResult;
132	  }
133	
134	  const totalPremium = calculateItemPremiums(items) + getProcessingFee(items.length);
135	  const hasFirstInsurance = items.some(item => item.firstInsurance);
136	  const hasFollowUpContract = items.some(item => item.followUpContract);
137	  const hasLongStandingCustomer = items.some(item => item.yearsWithMHPCO && item.yearsWithMHPCO >= LONG_STANDING_CUSTOMER_THRESHOLD);
138	
139	  let finalPremium = applyFirstInsuranceSurcharge(totalPremium, hasFirstInsurance);
140	  finalPremium = applyFollowUpContractDiscount(finalPremium, hasFollowUpContract);
141	  finalPremium = applyLongStandingCustomerDiscount(finalPremium, hasLongStandingCustomer);
142	  return finalPremium;
143	}
144	
145	export function claim(): number {
146	  throw new Error("Not implemented");
147	}
